import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import TicketVenta from "../components/TicketVenta";
import { FaSearch, FaCartPlus, FaCashRegister, FaUser } from "react-icons/fa";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  const [clienteNombre, setClienteNombre] = useState("");
  const [clienteApellido, setClienteApellido] = useState("");
  const [clienteTelefono, setClienteTelefono] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [carrito, setCarrito] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/productos`);
      setProductos(res.data);
    } catch (err) {
      console.error("❌ Error al obtener productos:", err);
    }
  };

  const obtenerClientes = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/clientes`);
      setClientes(res.data);
    } catch (err) {
      console.error("❌ Error al obtener clientes:", err);
    }
  };

  const buscarProducto = (texto) => {
    setBusquedaProducto(texto);
    const producto = productos.find((p) =>
      (p.nombre || "").toLowerCase().includes(texto.toLowerCase())
    );
    setProductoSeleccionado(producto || null);
    setMensaje("");
  };

  const agregarAlCarrito = () => {
    if (!productoSeleccionado || cantidad <= 0) return;

    const stockActual = Number(productoSeleccionado.stock || 0);
    const prodID = productoSeleccionado._id; // Ajuste para MongoDB Atlas
    const precioUnitario = Number(productoSeleccionado.precio);
    const nombreProd = productoSeleccionado.nombre;

    if (stockActual < cantidad) {
      setMensaje(`❌ Stock insuficiente. Disponible: ${stockActual}`);
      return;
    }

    const existente = carrito.find((p) => p.ProductID === prodID);

    if (existente) {
      if (existente.Cantidad + cantidad > stockActual) {
        setMensaje("❌ No puedes agregar más de lo disponible en stock");
        return;
      }
      setCarrito(
        carrito.map((p) =>
          p.ProductID === prodID
            ? { ...p, Cantidad: p.Cantidad + cantidad }
            : p
        )
      );
    } else {
      setCarrito([
        ...carrito,
        {
          ProductID: prodID,
          Nombre: nombreProd,
          Cantidad: cantidad,
          PrecioUnitario: precioUnitario,
        },
      ]);
    }

    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setCantidad(1);
    setMensaje("✅ Producto añadido");
    setTimeout(() => setMensaje(""), 2000);
  };

  const quitarDelCarrito = (id) => {
    setCarrito(carrito.filter(p => p.ProductID !== id));
  };

  const calcularSubtotal = () =>
    carrito.reduce((acc, p) => acc + p.Cantidad * p.PrecioUnitario, 0);

  const realizarVenta = async () => {
    if (!clienteNombre.trim() || !clienteApellido.trim()) {
      setMensaje("⚠️ Ingresa nombre y apellido del cliente.");
      return;
    }

    setLoading(true);
    try {
      let clienteExistente = clientes.find(
        (c) =>
          (c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
          (c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
      );

      const payload = {
        ClienteID: clienteExistente?._id || null,
        Nombre: clienteNombre,
        Apellido: clienteApellido,
        Telefono: clienteTelefono || "",
        productos: carrito.map((p) => ({
          ProductID: p.ProductID,
          Cantidad: p.Cantidad
        }))
      };

      const res = await axios.post(`${API_URL}/api/ventas/registrar`, payload);

      setTicket(res.data);
      setMensaje("✅ Venta realizada con éxito.");
      setCarrito([]);
      setClienteNombre("");
      setClienteApellido("");
      setClienteTelefono("");
      obtenerProductos();
      obtenerClientes();
    } catch (err) {
      const msgError = err.response?.data?.mensaje || err.message;
      setMensaje(`❌ Error: ${msgError}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container-fluid p-4 bg-light min-vh-100">
      <div className="d-flex align-items-center mb-4">
        <FaCashRegister className="fs-2 text-primary me-3" />
        <h2 className="fw-bold mb-0">Punto de Venta (POS)</h2>
      </div>

      <div className="row">
        {/* PANEL IZQUIERDO: SELECCIÓN */}
        <div className="col-lg-7">
          <div className="card shadow-sm border-0 p-4 mb-4">
            <h5 className="fw-bold mb-3"><FaSearch className="me-2 text-secondary" /> 1. Buscar Productos</h5>
            <div className="input-group mb-3 shadow-sm">
              <span className="input-group-text bg-white border-end-0"><FaSearch className="text-muted" /></span>
              <input
                type="text"
                className="form-control border-start-0"
                placeholder="Escriba el nombre del producto..."
                value={busquedaProducto}
                onChange={(e) => buscarProducto(e.target.value)}
                list="listaProductos"
              />
            </div>
            <datalist id="listaProductos">
              {productos.map((p) => (
                <option key={p._id} value={p.nombre} />
              ))}
            </datalist>

            {productoSeleccionado && (
              <div className="card bg-primary text-white border-0 shadow-sm p-3 mb-4 animate__animated animate__fadeIn">
                <div className="d-flex justify-content-between align-items-center">
                  <div>
                    <h5 className="mb-1 fw-bold">{productoSeleccionado.nombre}</h5>
                    <p className="mb-0 small opacity-75">Precio: ${productoSeleccionado.precio} | Stock: {productoSeleccionado.stock}</p>
                  </div>
                  <div className="d-flex gap-2">
                    <input
                      type="number"
                      className="form-control form-control-sm text-center fw-bold"
                      style={{ width: "70px" }}
                      min="1"
                      value={cantidad}
                      onChange={(e) => setCantidad(Number(e.target.value))}
                    />
                    <button className="btn btn-light btn-sm fw-bold" onClick={agregarAlCarrito}>
                      <FaCartPlus className="me-1" /> Agregar
                    </button>
                  </div>
                </div>
              </div>
            )}

            <h5 className="fw-bold mb-3 mt-2"><FaUser className="me-2 text-secondary" /> 2. Datos del Cliente</h5>
            <div className="row g-3">
              <div className="col-md-6">
                <input className="form-control bg-light border-0" placeholder="Nombre" value={clienteNombre} onChange={(e) => setClienteNombre(e.target.value)} />
              </div>
              <div className="col-md-6">
                <input className="form-control bg-light border-0" placeholder="Apellido" value={clienteApellido} onChange={(e) => setClienteApellido(e.target.value)} />
              </div>
              <div className="col-12">
                <input className="form-control bg-light border-0" placeholder="Teléfono (Opcional)" value={clienteTelefono} onChange={(e) => setClienteTelefono(e.target.value)} />
              </div>
            </div>

            {mensaje && (
              <div className={`alert mt-4 border-0 shadow-sm animate__animated animate__shakeX ${mensaje.includes('✅') ? 'alert-success' : 'alert-danger'}`}>
                {mensaje}
              </div>
            )}
          </div>
        </div>

        {/* PANEL DERECHO: CARRITO */}
        <div className="col-lg-5">
          <div className="card shadow-sm border-0 p-4 bg-white h-100">
            <h5 className="fw-bold text-dark mb-4 border-bottom pb-2">🛒 Carrito de Compras</h5>
            <div className="table-responsive flex-grow-1" style={{ minHeight: "300px" }}>
              {carrito.length === 0 ? (
                <div className="text-center py-5">
                  <p className="text-muted mt-5">El carrito está vacío</p>
                </div>
              ) : (
                <table className="table table-hover align-middle">
                  <thead className="table-light">
                    <tr>
                      <th>Producto</th>
                      <th className="text-center">Cant.</th>
                      <th className="text-end">Subtotal</th>
                      <th></th>
                    </tr>
                  </thead>
                  <tbody>
                    {carrito.map((p, i) => (
                      <tr key={i}>
                        <td className="small fw-bold">{p.Nombre}</td>
                        <td className="text-center"><span className="badge bg-secondary">{p.Cantidad}</span></td>
                        <td className="text-end fw-bold">${(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                        <td className="text-end">
                           <button className="btn btn-link text-danger p-0" onClick={() => quitarDelCarrito(p.ProductID)}>✕</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>

            <div className="mt-auto pt-3 border-top">
              <div className="d-flex justify-content-between fs-6 text-muted mb-1">
                <span>Subtotal:</span>
                <span>${calcularSubtotal().toFixed(2)}</span>
              </div>
              <div className="d-flex justify-content-between fs-6 text-muted mb-3">
                <span>IVA (13%):</span>
                <span>${(calcularSubtotal() * 0.13).toFixed(2)}</span>
              </div>
              <div className="d-flex justify-content-between fs-2 fw-bold text-success">
                <span>Total:</span>
                <span>${(calcularSubtotal() * 1.13).toFixed(2)}</span>
              </div>

              <button
                className="btn btn-success btn-lg w-100 mt-4 shadow fw-bold py-3"
                onClick={realizarVenta}
                disabled={carrito.length === 0 || loading}
              >
                {loading ? <span className="spinner-border spinner-border-sm me-2"></span> : "💰 CONFIRMAR VENTA"}
              </button>
            </div>
          </div>
        </div>
      </div>

      {ticket && <TicketVenta ticket={ticket} setTicket={setTicket} />}
    </div>
  );
}
